let res = [];
for (const item of $input.all()) {
    let itemJson = item.json;

    // 转换 procedure_scheduling 为对应的字符串描述
    switch (itemJson.procedure_scheduling) {
        case 1:
            itemJson.scheduling_description = "前加工";
            break;
        case 2:
            itemJson.scheduling_description = "组装测试";
            break;
        case 3:
            itemJson.scheduling_description = "成品测试";
            break;
        case 4:
            itemJson.scheduling_description = "包装";
            break;
        case 5:
            itemJson.scheduling_description = "维修";
            break;
        default:
            itemJson.scheduling_description = "未知";
    }

    // procedure_dataupload 2为true，1为false
    itemJson.procedure_dataupload_bool = itemJson.procedure_dataupload === 2;

    // 转换 procedure_type 字段（假设你有这个字段）
    if (itemJson.procedure_type !== undefined) {
        switch (itemJson.procedure_type) {
            case 1:
                itemJson.procedure_type_desc = "无需上传数据";
                break;
            case 2:
                itemJson.procedure_type_desc = "需要上传数据";
                break;
            default:
                itemJson.procedure_type_desc = "未知";
        }
    }

    res.push(itemJson);
}

return {
    result: res
};
